	import {
		createRouter,
		createWebHashHistory
	} from 'vue-router'
	import news from '@/views/news/list'
	import biaoqian from '@/views/biaoqian/list'
	import fuwuxiadan from '@/views/fuwuxiadan/list'
	import sheyinghuodong from '@/views/sheyinghuodong/list'
	import discusssheyingfuwu from '@/views/discusssheyingfuwu/list'
	import discusssheyingzuopin from '@/views/discusssheyingzuopin/list'
	import syslog from '@/views/syslog/list'
    import menu_manage from '@/views/menu_manage/list'
	import storeup from '@/views/storeup/list'
	import fuwuleixing from '@/views/fuwuleixing/list'
	import users from '@/views/users/list'
	import shangjia from '@/views/shangjia/list'
	import forum from '@/views/forum/list'
	import zuopinfenlei from '@/views/zuopinfenlei/list'
	import yonghu from '@/views/yonghu/list'
	import huodongbaoming from '@/views/huodongbaoming/list'
	import sheyingfuwu from '@/views/sheyingfuwu/list'
	import sheyingzuopin from '@/views/sheyingzuopin/list'
	import toupiaoxinxi from '@/views/toupiaoxinxi/list'
	import fuwuwancheng from '@/views/fuwuwancheng/list'
	import config from '@/views/config/list'
	import huodongleixing from '@/views/huodongleixing/list'
	import fuwujiedan from '@/views/fuwujiedan/list'
	import shangjiaRegister from '@/views/shangjia/register'
	import shangjiaCenter from '@/views/shangjia/center'

export const routes = [{
		path: '/login',
		name: 'login',
		component: () => import('../views/login.vue')
	},{
		path: '/',
		name: '首页',
		component: () => import('../views/index'),
		children: [{
			path: '/',
			name: '首页',
			component: () => import('../views/HomeView.vue'),
			meta: {
				affix: true
			}
		}, {
			path: '/updatepassword',
			name: '修改密码',
			component: () => import('../views/updatepassword.vue')
		}
		
		,{
			path: '/shangjiaCenter',
			name: '商家个人中心',
			component: shangjiaCenter
		}
		,{
			path: '/news',
			name: '通知推送',
			component: news
		}
		,{
			path: '/biaoqian',
			name: '标签',
			component: biaoqian
		}
		,{
			path: '/fuwuxiadan',
			name: '服务下单',
			component: fuwuxiadan
		}
		,{
			path: '/sheyinghuodong',
			name: '摄影活动',
			component: sheyinghuodong
		}
		,{
			path: '/discusssheyingfuwu',
			name: '摄影服务评论-评论',
			component: discusssheyingfuwu
		}
		,{
			path: '/discusssheyingzuopin',
			name: '摄影作品评论-评论',
			component: discusssheyingzuopin
		}
		,{
			path: '/syslog',
			name: '操作日志',
			component: syslog
		}
        ,{
            path: '/menu',
            name: '菜单权限管理',
            component: menu_manage
        }
		,{
			path: '/storeup',
			name: '我的收藏',
			component: storeup
		}
		,{
			path: '/fuwuleixing',
			name: '服务类型',
			component: fuwuleixing
		}
		,{
			path: '/users',
			name: '管理员',
			component: users
		}
		,{
			path: '/shangjia',
			name: '商家',
			component: shangjia
		}
		,{
			path: '/forum',
			name: '我的发布',
			component: forum
		}
		,{
			path: '/zuopinfenlei',
			name: '作品分类',
			component: zuopinfenlei
		}
		,{
			path: '/yonghu',
			name: '用户',
			component: yonghu
		}
		,{
			path: '/huodongbaoming',
			name: '活动报名',
			component: huodongbaoming
		}
		,{
			path: '/sheyingfuwu',
			name: '摄影服务',
			component: sheyingfuwu
		}
		,{
			path: '/sheyingzuopin',
			name: '摄影作品',
			component: sheyingzuopin
		}
		,{
			path: '/toupiaoxinxi',
			name: '投票信息',
			component: toupiaoxinxi
		}
		,{
			path: '/fuwuwancheng',
			name: '服务完成',
			component: fuwuwancheng
		}
		,{
			path: '/config',
			name: '轮播图',
			component: config
		}
		,{
			path: '/huodongleixing',
			name: '活动类型',
			component: huodongleixing
		}
		,{
			path: '/fuwujiedan',
			name: '服务接单',
			component: fuwujiedan
		}
		]
	},
	{
		path: '/shangjiaRegister',
		name: '商家注册',
		component: shangjiaRegister
	},
]

const router = createRouter({
	history: createWebHashHistory(process.env.BASE_URL),
	routes
})

export default router
