<template>
	<div>
		<el-dialog modal-class="edit_form_modal" class="edit_form" v-model="formVisible" :title="formTitle" width="80%" destroy-on-close :fullscreen='false'>
			<el-form class="formModel_form" ref="formRef" :model="form" :rules="rules">
				<el-row >
					<el-col :span="12">
						<el-form-item label="服务名称" prop="fuwumingcheng">
							<el-input class="list_inp" v-model="form.fuwumingcheng" placeholder="服务名称"
                                type="text"
								:readonly="!isAdd||disabledForm.fuwumingcheng?true:false" />
						</el-form-item>
					</el-col>

					<el-col :span="12">
						<el-form-item label="服务类型" prop="fuwuleixing">
							<el-select
								class="list_sel"
								:disabled="!isAdd||disabledForm.fuwuleixing?true:false"
								v-model="form.fuwuleixing" 
								placeholder="请选择服务类型"
								>
								<el-option v-for="(item,index) in fuwuleixingLists" :label="item"
									:value="item"
									>
								</el-option>
							</el-select>
						</el-form-item>
					</el-col>
					<el-col :span="12">
						<el-form-item label="服务时间" prop="fuwushijian">
							<el-input class="list_inp" v-model="form.fuwushijian" placeholder="服务时间"
                                type="text"
								:readonly="!isAdd||disabledForm.fuwushijian?true:false" />
						</el-form-item>
					</el-col>

					<el-col :span="12">
						<el-form-item label="价格" prop="jiage">
							<el-input class="list_inp" v-model.number="form.jiage" placeholder="价格"
                                type="number"
                                @mousewheel.native.prevent
								:readonly="!isAdd||disabledForm.jiage?true:false" />
						</el-form-item>
					</el-col>

					<el-col :span="12">
						<el-form-item prop="tupian"
									  label="图片"
						>
							<uploads
								:disabled="!isAdd||disabledForm.tupian?true:false"
								action="file/upload"
								tip="请上传图片"
								style="width: 100%;text-align: left;"
								:fileUrls="form.tupian?form.tupian:''" 
								@change="tupianUploadSuccess">
							</uploads>
						</el-form-item>
					</el-col>
					<el-col :span="12">
						<el-form-item label="摄影师账号" prop="sheyingshizhanghao">
							<el-input class="list_inp" v-model="form.sheyingshizhanghao" placeholder="摄影师账号"
                                type="text"
								:readonly="!isAdd||disabledForm.sheyingshizhanghao?true:false" />
						</el-form-item>
					</el-col>

					<el-col :span="12">
						<el-form-item label="摄影师姓名" prop="sheyingshixingming">
							<el-input class="list_inp" v-model="form.sheyingshixingming" placeholder="摄影师姓名"
                                type="text"
								:readonly="!isAdd||disabledForm.sheyingshixingming?true:false" />
						</el-form-item>
					</el-col>

					<el-col :span="12">
						<el-form-item label="摄影教程" prop="sheyingjiaocheng">
							<uploads
								:disabled="!isAdd||disabledForm.sheyingjiaocheng?true:false"
								type="file"
								action="file/upload" 
								tip="请上传摄影教程" 
								:limit="1" 
								style="width: 100%;text-align: left;"
								:fileUrls="form.sheyingjiaocheng?form.sheyingjiaocheng:''" 
								@change="sheyingjiaochengUploadSuccess">
							</uploads>
						</el-form-item>
					</el-col>
					<el-col :span="12">
						<el-form-item label="服务详情" prop="fuwuxiangqing">
							<el-input v-model="form.fuwuxiangqing" placeholder="服务详情" type="textarea"
							:readonly="!isAdd||disabledForm.fuwuxiangqing?true:false"
							/>
						</el-form-item>
					</el-col>
				</el-row>
			</el-form>
			<template #footer v-if="isAdd||type=='logistics'||type=='reply'">
				<span class="formModel_btn_box">
					<el-button class="cancel_btn" @click="closeClick">取消</el-button>
					<el-button class="confirm_btn" type="primary" @click="save"
						>
						提交
					</el-button>
				</span>
			</template>
		</el-dialog>
	</div>
</template>
<script setup>
	import {
		reactive,
		ref,
		getCurrentInstance,
		nextTick,
		computed,
		defineEmits
	} from 'vue'
    import {
        useStore
    } from 'vuex';
    const store = useStore()
    const user = computed(()=>store.getters['user/session'])
	const context = getCurrentInstance()?.appContext.config.globalProperties;	
	const emit = defineEmits(['formModelChange'])
	//基础信息
	const tableName = 'sheyingfuwu'
	const formName = '摄影服务'
	//基础信息
	//form表单
	const form = ref({})
	const disabledForm = ref({
        fuwumingcheng : false,
        fuwuleixing : false,
        fuwushijian : false,
        jiage : false,
        fuwuxiangqing : false,
        tupian : false,
        sheyingshizhanghao : false,
        sheyingshixingming : false,
        thumbsupNumber : false,
        crazilyNumber : false,
        storeupNumber : false,
        discussNumber : false,
        sheyingjiaocheng : false,
	})
	const formVisible = ref(false)
	const isAdd = ref(false)
	const formTitle = ref('')
    
	const rules = ref({
		fuwumingcheng: [
		],
		fuwuleixing: [
		],
		fuwushijian: [
		],
		jiage: [
			{ validator: context.$toolUtil.validator.number, trigger: 'blur' },
		],
		fuwuxiangqing: [
		],
		tupian: [
		],
		sheyingshizhanghao: [
		],
		sheyingshixingming: [
		],
		thumbsupNumber: [
			{ validator: context.$toolUtil.validator.intNumber, trigger: 'blur' },
		],
		crazilyNumber: [
			{ validator: context.$toolUtil.validator.intNumber, trigger: 'blur' },
		],
		storeupNumber: [
			{ validator: context.$toolUtil.validator.intNumber, trigger: 'blur' },
		],
		discussNumber: [
			{ validator: context.$toolUtil.validator.intNumber, trigger: 'blur' },
		],
		sheyingjiaocheng: [
		],
	})
	//表单验证
	
	const formRef = ref(null)
	const id = ref(0)
	const type = ref('')
	//服务类型列表
	const fuwuleixingLists = ref([])
	//图片上传回调
	const tupianUploadSuccess=(e)=>{
		form.value.tupian = e
	}
	//摄影教程上传回调
	const sheyingjiaochengUploadSuccess=(e)=>{
		form.value.sheyingjiaocheng = e
	}

	//获取唯一标识
	const getUUID =()=> {
      return new Date().getTime();
    }
	//重置
	const resetForm = () => {
		form.value = {
			fuwumingcheng: '',
			fuwuleixing: '',
			fuwushijian: '',
			jiage: '',
			fuwuxiangqing: '',
			tupian: '',
			sheyingshizhanghao: '',
			sheyingshixingming: '',
			sheyingjiaocheng: '',
		}
	}
	//获取info
	const getInfo = ()=>{
		context?.$http({
			url: `${tableName}/info/${id.value}`,
			method: 'get'
		}).then(res => {
			let reg=new RegExp('../../../file','g')
			form.value = res.data.data
			formVisible.value = true
		})
	}
	const crossRow = ref('')
	const crossTable = ref('')
	const crossTips = ref('')
	const crossColumnName = ref('')
	const crossColumnValue = ref('')
	//初始化
	const init=(formId=null,formType='add',formNames='',row=null,table=null,statusColumnName=null,tips=null,statusColumnValue=null)=>{
		resetForm()
		if(formId){
			id.value = formId
			type.value = formType
		}
		if(formType == 'add'){
			isAdd.value = true
			formTitle.value = '新增' + formName
			formVisible.value = true
		}else if(formType == 'info'){
			isAdd.value = false
			formTitle.value = '查看' + formName
			getInfo()
		}else if(formType == 'edit'){
			isAdd.value = true
			formTitle.value = '修改' + formName
			getInfo()
		}
		else if(formType == 'cross'){
			isAdd.value = true
			formTitle.value = formNames
			// getInfo()
			for(let x in row){
				if(x=='fuwumingcheng'){
					form.value.fuwumingcheng = row[x];
					disabledForm.value.fuwumingcheng = true;
					continue;
				}
				if(x=='fuwuleixing'){
					form.value.fuwuleixing = row[x];
					disabledForm.value.fuwuleixing = true;
					continue;
				}
				if(x=='fuwushijian'){
					form.value.fuwushijian = row[x];
					disabledForm.value.fuwushijian = true;
					continue;
				}
				if(x=='jiage'){
					form.value.jiage = row[x];
					disabledForm.value.jiage = true;
					continue;
				}
				if(x=='fuwuxiangqing'){
					form.value.fuwuxiangqing = row[x];
					disabledForm.value.fuwuxiangqing = true;
					continue;
				}
				if(x=='tupian'){
					form.value.tupian = row[x];
					disabledForm.value.tupian = true;
					continue;
				}
				if(x=='sheyingshizhanghao'){
					form.value.sheyingshizhanghao = row[x];
					disabledForm.value.sheyingshizhanghao = true;
					continue;
				}
				if(x=='sheyingshixingming'){
					form.value.sheyingshixingming = row[x];
					disabledForm.value.sheyingshixingming = true;
					continue;
				}
				if(x=='thumbsupNumber'){
					form.value.thumbsupNumber = row[x];
					disabledForm.value.thumbsupNumber = true;
					continue;
				}
				if(x=='crazilyNumber'){
					form.value.crazilyNumber = row[x];
					disabledForm.value.crazilyNumber = true;
					continue;
				}
				if(x=='storeupNumber'){
					form.value.storeupNumber = row[x];
					disabledForm.value.storeupNumber = true;
					continue;
				}
				if(x=='discussNumber'){
					form.value.discussNumber = row[x];
					disabledForm.value.discussNumber = true;
					continue;
				}
				if(x=='sheyingjiaocheng'){
					form.value.sheyingjiaocheng = row[x];
					disabledForm.value.sheyingjiaocheng = true;
					continue;
				}
			}
			if(row){
				crossRow.value = row
			}
			if(table){
				crossTable.value = table
			}
			if(tips){
				crossTips.value = tips
			}
			if(statusColumnName){
				crossColumnName.value = statusColumnName
			}
			if(statusColumnValue){
				crossColumnValue.value = statusColumnValue
			}
			formVisible.value = true
		}

		context?.$http({
			url: `${context?.$toolUtil.storageGet('sessionTable')}/session`,
			method: 'get'
		}).then(res => {
			var json = res.data.data
			if(json.hasOwnProperty('sheyingshizhanghao')&& context?.$toolUtil.storageGet("role")!="管理员"){
				form.value.sheyingshizhanghao = json.sheyingshizhanghao
				disabledForm.value.sheyingshizhanghao = true;
			}
			if(json.hasOwnProperty('sheyingshixingming')&& context?.$toolUtil.storageGet("role")!="管理员"){
				form.value.sheyingshixingming = json.sheyingshixingming
				disabledForm.value.sheyingshixingming = true;
			}
		})
		context?.$http({
			url: `option/fuwuleixing/fuwuleixing`,
			method: 'get'
		}).then(res=>{
			fuwuleixingLists.value = res.data.data
		})
	}
	//初始化
	//声明父级调用
	defineExpose({
		init
	})
	//关闭
	const closeClick = () => {
		formVisible.value = false
	}
	//富文本
	const editorChange = (e,name) =>{
		form.value[name] = e
	}
	//提交
	const save= async ()=>{
		if(form.value.tupian!=null) {
			form.value.tupian = form.value.tupian.replace(new RegExp(context?.$config.url,"g"),"");
		}
		if(form.value.sheyingjiaocheng!=null) {
			form.value.sheyingjiaocheng = form.value.sheyingjiaocheng.replace(new RegExp(context?.$config.url,"g"),"");
		}
		var table = crossTable.value
		var objcross = JSON.parse(JSON.stringify(crossRow.value))
		let crossUserId = ''
		let crossRefId = ''
		let crossOptNum = ''
		if(type.value == 'cross'){
			if(crossColumnName.value!=''){
				if(!crossColumnName.value.startsWith('[')){
					for(let o in objcross){
						if(o == crossColumnName.value){
							objcross[o] = crossColumnValue.value
						}
					}
					//修改跨表数据
					changeCrossData(objcross)
				}else{
					crossUserId = user.value.id
					crossRefId = objcross['id']
					crossOptNum = crossColumnName.value.replace(/\[/,"").replace(/\]/,"")
				}
			}
		}
		formRef.value.validate((valid)=>{
			if(valid){
				if(crossUserId&&crossRefId){
					form.value.crossuserid = crossUserId
					form.value.crossrefid = crossRefId
					let params = {
						page: 1,
						limit: 1000, 
						crossuserid:form.value.crossuserid,
						crossrefid:form.value.crossrefid,
					}
					context?.$http({
						url: `${tableName}/page`,
						method: 'get', 
						params: params 
					}).then(res=>{
						if(res.data.data.total>=crossOptNum){
							context?.$toolUtil.message(`${crossTips.value}`,'error')
							return false
						}else{
							context?.$http({
								url: `${tableName}/${!form.value.id ? "save" : "update"}`,
								method: 'post', 
								data: form.value 
							}).then(async res=>{
								emit('formModelChange')
								context?.$toolUtil.message(`操作成功`,'success')
                                formVisible.value = false
							})
						}
					})
				}else{
					context?.$http({
						url: `${tableName}/${!form.value.id ? "save" : "update"}`,
						method: 'post', 
						data: form.value 
					}).then(async (res)=>{
						emit('formModelChange')
						context?.$toolUtil.message(`操作成功`,'success')
                        formVisible.value = false
					})
				}
			}else{
                context.$message.error('请完善信息')
            }
		})
	}
	//修改跨表数据
	const changeCrossData = async (row)=>{
        if(type.value == 'cross'){
            await context?.$http({
                url: `${crossTable.value}/update`,
                method: 'post',
                data: row
            }).then(res=>{})
        }
	}
</script>
